# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from prometheus_client import start_http_server, Summary, Counter

# Create a new metric for each unique user-path combination
user_path_metrics = {}

def track_request(user_id, session_id, request_path):
    # Create a new metric if it doesn't exist
    if (user_id, request_path) not in user_path_metrics:
        user_path_metrics[(user_id, request_path)] = Counter(
            f"user_{user_id}_path_{request_path}",
            "Number of requests for this user and path",
            labelnames=["session_id"],
        )

    # Increment the metric for this user and path
    user_path_metrics[(user_id, request_path)].labels(session_id=session_id).inc()

# Start the Prometheus HTTP server
start_http_server(8000)

# Track HTTP requests
track_request("user1", "session1", "/path1")
track_request("user1", "session2", "/path2")
track_request("user2", "session3", "/path1")